class TickerWidget extends StatefulWidget {
  const TickerWidget({super.key, required this.events});
  final Stream<int> events;
  @override State<TickerWidget> createState() => _TickerWidgetState();
}

class _TickerWidgetState extends State<TickerWidget> {
  StreamSubscription<int>? _sub;
  int _last = 0;

  @override
  void initState() {
    super.initState();
    _sub = widget.events.listen(
      (v) {
        if (!mounted) return;       // ✅ guard against late events
        setState(() => _last = v);
      },
      onError: (Object e, StackTrace s) => debugPrint('stream err: $e'),
      onDone: () => debugPrint('stream done'),
      cancelOnError: false,         // keep subscribed after errors
    );
  }

  // React to the parent passing a different stream
  @override
  void didUpdateWidget(covariant TickerWidget old) {
    super.didUpdateWidget(old);
    if (old.events != widget.events) {
      _sub?.cancel();               // ✅ drop the old subscription
      _sub = widget.events.listen((v) => setState(() => _last = v));
    }
  }

  @override
  void dispose() {
    _sub?.cancel();                 // ✅ critical — prevents leaks
    super.dispose();
  }

  @override Widget build(_) => Text('$_last');
}

// ── Pause / resume — useful for app lifecycle ──
class _PausableState extends State<MyWidget> with WidgetsBindingObserver {
  StreamSubscription? _sub;

  @override void didChangeAppLifecycleState(AppLifecycleState s) {
    if (s == AppLifecycleState.paused)  _sub?.pause();
    if (s == AppLifecycleState.resumed) _sub?.resume();
  }
}

