// ── await for — sequential, easy to read ──
Future<void> processOrders(Stream<Order> incoming) async {
  await for (final order in incoming) {
    try {
      // ✅ The next event won't be delivered until this finishes — backpressure
      await orders.persist(order);
      await analytics.track('order_received', order.id);
    } catch (e) {
      log('order failed: $e');
      // continue with next event
    }
  }
  log('stream finished');
}

// ── listen — reactive, concurrent handlers ──
void trackUserActivity(Stream<UserEvent> events) {
  events.listen(
    (event) async {
      // Each event fires async; multiple may run in parallel
      await analytics.send(event);
    },
    onError: (Object e, StackTrace s) => crashlytics.recordError(e, s),
    onDone: () => log('events stream closed'),
    cancelOnError: false,
  );
}

// ── Inside async*: await for + yield to transform ──
Stream<HttpResponse> retryOnce(Stream<HttpRequest> requests) async* {
  await for (final req in requests) {
    try {
      yield await http.send(req);
    } catch (_) {
      // Retry once — sequential semantics make this simple
      yield await http.send(req);
    }
  }
}

