// ── handleError as a pipeline filter ──
Stream<int> safe(Stream<int> input) =>
    input.handleError(
      (e, s) => log('skipped bad value: $e'),
      test: (e) => e is FormatException, // only swallow FormatException
    );

// ── transform errors into typed events (Result-style) ──
Stream<Result<T>> safer<T>(Stream<T> input) =>
    input.transform(StreamTransformer<T, Result<T>>.fromHandlers(
      handleData: (data, sink) => sink.add(Result.ok(data)),
      handleError: (e, s, sink) => sink.add(Result.err(e)),
    ));

// Consumer never deals with raw errors
await for (final r in safer(api.search('flutter'))) {
  switch (r) {
    case Ok(:final value): show(value);
    case Err(:final error): show('skip: $error');
  }
}

