// ── Bloc style: turn errors into states ──
Stream<UiState> reduce(Stream<Event> events) async* {
  await for (final event in events) {
    yield Loading();
    try {
      yield Loaded(await event.fetch());
    } catch (e) {
      yield Failed(e);                    // never close the stream
    }
  }
}

